import{_ as r,X as t,Y as s,Z as a,a0 as i,a1 as d,a2 as o,$ as e,F as c}from"./framework-7663974c.js";const p="/assets/服务目录-6f44a0df.png",h="/assets/职责矩阵-4a0ff34b.png",l="/assets/二线支持流程-0e8ecc3c.png",g="/assets/4eb16cba-35cc-4699-8451-2f605ff98e1e-856781ab.png",f="/assets/01b923e1-1f25-4e5d-9a6f-b962d1a08f4c-23a974df.png",_={},u=e('<p>2021年12月底的时候，向老板提出了从产研团队退出的事情，将工作交由另一个小伙伴负责。我个人计划是，好好搞搞云原生运维的事情。</p><p>但，事与愿违😂</p><p>感觉也没过几天，刚准备午休，突然被告知，老板在茶水间等我。我顺着茶水间的路，往前走着，心里却思考着其他的事情，什么事情呢？难道又要回去带团队？🙅那我指定不干。就这样走到了茶水间。</p><p>茶水间整体的气氛，给人的感觉是较为轻松的。</p><p>行吧，聊吧～不想了。就一屁股坐下了。十几分钟过去后，我又领了个艰巨的任务。</p><p><code>公司要成立个团队，把项目上的运维工程师，收过来，统一管理</code>。但这个事情的背景，极其复杂...第一感觉就是，这还不如带产研...</p><p>目前的背景是</p><ol><li>产线的运维管理都是各个产线自己负责的</li><li>交付的工程师，属于交付团队</li><li>售前的工程师，属于售前团队</li><li>售后的工程师，属于售后团队</li></ol><p>把这些人都收回来，这动作也太大了, 之后用人和管理等诸多事情，跨团队合作...事情永远远比想象中复杂</p><p>经过了一个月的调研，一个月的思考。最终出了一个团队规划，并完善了相关的细节点</p><h2 id="团队规划" tabindex="-1"><a class="header-anchor" href="#团队规划" aria-hidden="true">#</a> 团队规划</h2><p>先聚后散。</p><p>聚，是为了通过大家一起努力，把体系建立起来，大家有规范、有标准、有积累、有成长。 散，散是为了更好的将工程师能力，输出并赋能其他团队</p><h3 id="目标" tabindex="-1"><a class="header-anchor" href="#目标" aria-hidden="true">#</a> 目标</h3><p>一线转二线，对内提供产线、售前、交付、售后支撑，同时对外提供服务支持，逐步形成以内部运维团队为基础，驱动公司运维相关的工作的高效运转与合理分配</p><h3 id="专业化分工" tabindex="-1"><a class="header-anchor" href="#专业化分工" aria-hidden="true">#</a> 专业化分工</h3><p>通过产线、职责的专业划分，让运维人员可以在自己所负责的模块做的更深入，更专业，从而更好的完成岗位职责，产出专业的知识文档，赋能内部团队以及服务商。</p><p>具体职责详情：</p>',18),m=e('<figure><img src="'+p+'" alt="服务目录截图" tabindex="0" loading="lazy"><figcaption>服务目录截图</figcaption></figure><figure><img src="'+h+'" alt="职责矩阵" tabindex="0" loading="lazy"><figcaption>职责矩阵</figcaption></figure><p>由于人员有限，项目较多，单个人员会负责多个项目，形成主备关系，当主负责人不在岗位的时候，如调休、请假等，则另一人顶替工作。在日常工作中，产线负责人会进行培训和分享，尽可能的拉齐各成员间的专业水平</p><p>专业化的分工，提升了团队成员工作的专注力，降低琐事的消耗，起到一定的降噪作用，从而提升工作的质量和效率，但对协同办公的要求也\b相应的提高了，所以后续需尽可能多的自动化</p><h3 id="流程化服务" tabindex="-1"><a class="header-anchor" href="#流程化服务" aria-hidden="true">#</a> 流程化服务</h3><p>目前SRE运维的工作范围有云原生设计与维护，开发、测试环境维护与协助，生产运维，售前支持，售后支持，服务商支持，各种事项，繁杂琐碎，内外部人均有可能提出运维相关的需求，为统一入口，在DSM新增<strong>SRE技术支持</strong>和<strong>基础组件与微服务申请</strong>服务目录，统一进行工作安排和人员调度，避免工作杂乱无章，效率低下</p>',6),b=e('<figure><img src="'+l+'" alt="《二线技术支持流程》" tabindex="0" loading="lazy"><figcaption>《二线技术支持流程》</figcaption></figure><p>通过流程这个切入口，逐步将运维工作进行收口</p><h4 id="组件申请" tabindex="-1"><a class="header-anchor" href="#组件申请" aria-hidden="true">#</a> 组件申请</h4><figure><img src="'+g+'" alt="组件申请" tabindex="0" loading="lazy"><figcaption>组件申请</figcaption></figure><h4 id="技术支持" tabindex="-1"><a class="header-anchor" href="#技术支持" aria-hidden="true">#</a> 技术支持</h4><figure><img src="'+f+'" alt="技术支持" tabindex="0" loading="lazy"><figcaption>技术支持</figcaption></figure><h3 id="规范化操作" tabindex="-1"><a class="header-anchor" href="#规范化操作" aria-hidden="true">#</a> 规范化操作</h3><p>目前公司运维群体分为<strong>内部研发产线运维</strong>工程师以及服务商工程师，运维规范化操作主要是用来约束这两部分运维人员的操作行为。</p><p>目前内部运维产线运维，主要是云原生环境的维护，设计的主要内容除了常规的操作系统外，还涉及Kubernetes平台、业务编排以及运维监控、日志等等，云原生平台已有一系列的规范和流程支持，以确保各种变更操作等规范化，标准化，有迹可循**（运维即代码）**。</p><p>针对服务商，除了规范手册外，另提供了高危命令的规避工具用来规避部分高危操作</p>',10),x=e('<h3 id="自动化运维" tabindex="-1"><a class="header-anchor" href="#自动化运维" aria-hidden="true">#</a> 自动化运维</h3><p>公司产品整个研发架构是微服务架构，且涉及多语言(java golang python nodejs)，相关的服务配置越来越复杂，变动的波及面也越来越广，若没有规范化、自动化的服务支撑，则后续的工作越来越难展开，需要投入的人力越来越大，运维效率和质量就无法保证。</p><p>针对重复性、批量性的操作，运维需要开发自动化工具、平台或脚本，尽可能的做到自动执行、一键执行逐步实现运维自动化。</p><p>目前已有的自动化平台：</p><ol><li>管理平台</li><li>通知平台</li><li>脚本库</li><li>运维即代码</li></ol><h3 id="共享知识库" tabindex="-1"><a class="header-anchor" href="#共享知识库" aria-hidden="true">#</a> 共享知识库</h3><p>运维工作中，会遇到各种问题，总结各种经验和知识，对知识进行管理和收口，能更好的赋能团队以及部门，提升工作效率和质量。</p><p>知识库主要分为内部和外部两大类，内部知识库主要存放团队相关的资料和手册，方便组员进行信息的查找与对齐，避免出现过多的偏差。外部知识库主要存放项目实施相关手册和文档等，便于服务商的对接</p><h3 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h3><p>整体的规划以及有效落地，可搭建一个较为完整的运维体系，保证环境的稳定，提升运维质量和效率，到达降本增效的目的</p><h3 id="全览" tabindex="-1"><a class="header-anchor" href="#全览" aria-hidden="true">#</a> 全览</h3>',11),k={href:"https://www.yuque.com/dl1548/zili/guqohr?singleDoc#",target:"_blank",rel:"noopener noreferrer"};function v(y,L){const n=c("ExternalLinkIcon");return t(),s("div",null,[u,a(" [请至钉钉文档查看附件《服务目录与价值指标》](https://alidocs.dingtalk.com/i/nodes/B6L5QAmawMPJMAevQKNdJq1z09lnK3kb?iframeQuery=anchorId%253DX02l75k444ausogvtyq4d) "),m,a(" 具体流程见： [《二线技术支持流程》](https://docs.dingtalk.com/i/nodes/3Pl7jXNw6dBWxOr5Lvyd8vKAGqOzY0D9?nav=share&navQuery=spaceId%3D9JOGOLABLk96z4QL) "),b,a(" [《运维规范手册》](https://docs.dingtalk.com/i/nodes/e5vdDPq4wYa8aB9xD22kWj7nbm10NkB9?nav=share&navQuery=spaceId%3D9JOGOLABLk96z4QL) "),a(" ![image](https://alidocs.oss-cn-zhangjiakou.aliyuncs.com/res/7jP2lRWXD693n8g5/img/d62e3daa-75d3-4ec8-a6d6-55ac7f3f44a9.png) "),a(" [SRE内部手册](https://docs.dingtalk.com/i/nodes/OmLa2Gg0l5BW71b5bD6NJvQAdYbnKEek?nav=share&navQuery=spaceId%3D9JOGOV1JVkgjm4QL) "),x,i("p",null,[i("a",k,[d("产品运维体系 密码：qpmk"),o(n)])])])}const D=r(_,[["render",v],["__file","运维团队的建立.html.vue"]]);export{D as default};
